function randomDate(daysBack: number): string {
  const d = new Date()
  d.setDate(d.getDate() - Math.floor(Math.random() * daysBack))
  return d.toISOString().slice(0, 10)
}

function probForStage(stage: string): number {
  switch (stage) {
    case 'Discovery': return 10 + Math.floor(Math.random() * 20)
    case 'Proposal': return 30 + Math.floor(Math.random() * 25)
    case 'Negotiation': return 55 + Math.floor(Math.random() * 20)
    case 'Verbal Yes': return 80 + Math.floor(Math.random() * 15)
    case 'Closed Won': return 100
    case 'Closed Lost': return 0
    default: return 50
  }
}

